// TestHeartbeatRsp_ScalaDecode decodes the Scala HeartbeatRsp fixture and
// verifies the uid field (fixture uses uid=99).
func TestHeartbeatRsp_ScalaDecode(t *testing.T) {
	data := loadFixtureArtery(t, "artery_heartbeat_rsp.bin")
	rsp := &gproto.ArteryHeartbeatRsp{}
	if err := proto.Unmarshal(data, rsp); err != nil {
		t.Fatalf("proto.Unmarshal HeartbeatRsp: %v", err)
	}
	if rsp.GetUid() != 99 {
		t.Errorf("Uid = %d, want 99", rsp.GetUid())
	}
}

// TestHeartbeatRsp_GoMatchesScala encodes ArteryHeartbeatRsp in Go and verifies
// byte-identical output to the Scala fixture.
// uid=99 → 0x08 0x63 (field 1, varint 99)
func TestHeartbeatRsp_GoMatchesScala(t *testing.T) {
	scala := loadFixtureArtery(t, "artery_heartbeat_rsp.bin")
	rsp := &gproto.ArteryHeartbeatRsp{Uid: proto.Uint64(99)}
	got, err := proto.Marshal(rsp)
	if err != nil {
		t.Fatalf("proto.Marshal: %v", err)
	}
	if !bytes.Equal(got, scala) {
		t.Errorf("Go bytes = %x, Scala = %x", got, scala)
	}
}

// TestHeartbeatRsp_ExpectedBytes verifies the exact wire bytes for uid=99:
// 0x08 (field 1, varint) + 0x63 (99).
func TestHeartbeatRsp_ExpectedBytes(t *testing.T) {
	data := loadFixtureArtery(t, "artery_heartbeat_rsp.bin")
	want := []byte{0x08, 0x63}
	if !bytes.Equal(data, want) {
		t.Errorf("HeartbeatRsp bytes = %x, want %x", data, want)
	}
}

func TestHeartbeatRsp_RoundTrip(t *testing.T) {
	rsp := &gproto.ArteryHeartbeatRsp{Uid: proto.Uint64(123456789)}
	b, err := proto.Marshal(rsp)
	if err != nil {
		t.Fatalf("Marshal: %v", err)
	}
	got := &gproto.ArteryHeartbeatRsp{}
	if err := proto.Unmarshal(b, got); err != nil {
		t.Fatalf("Unmarshal: %v", err)
	}
	if got.GetUid() != 123456789 {
		t.Errorf("Uid = %d, want 123456789", got.GetUid())
	}
}

