// TestHandshakeReq_Size verifies the expected byte count for the fixture values.
// Computed from proto field layout:
//
//	from UniqueAddress (38 bytes) → total outer field: 40 bytes
//	to   Address (32 bytes)      → total outer field: 34 bytes
//	Total: 74 bytes
func TestHandshakeReq_Size(t *testing.T) {
	data := loadFixtureArtery(t, "artery_handshake_req.bin")
	if len(data) != 74 {
		t.Errorf("HandshakeReq fixture size = %d, want 74", len(data))
	}
}

// TestHeartbeatRsp_Size verifies the expected byte count for uid=99 (1-byte varint).
func TestHeartbeatRsp_Size(t *testing.T) {
	data := loadFixtureArtery(t, "artery_heartbeat_rsp.bin")
	if len(data) != 2 {
		t.Errorf("HeartbeatRsp fixture size = %d, want 2", len(data))
	}
}
